import QuizUI from '../../../components/QuizUI/QuizUI';

{/* क्या आप Destructuring के मास्टर हैं?<br/> */}
<p class="inset">या फिर यह आपकी <em>Symphony of Destruction?</em></p>

यह क्विज़ JavaScript में Destructuring के आपके ज्ञान की परख करेगा: "basic" ऑब्जेक्ट सिंटैक्स से लेकर नेस्टेड डिस्ट्रक्चरिंग और डिफ़ॉल्ट वैल्यूज़ तक। साथ ही, TypeScript और इनलाइन टाइप्स पर बोनस सवाल भी हैं!

वार्मअप से सीधे शुरू करें — अपनी Destructuring स्किल्स साबित करें! 👇

